import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [messages, setMessages] = useState([]);
  const [tab, setTab] = useState('users');
  const [themeTrigger, setThemeTrigger] = useState(false);

  // ================= FETCH DATA =================
  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
    API.get('/admin/comments').then(res => setComments(res.data));
    API.get('/admin/messages').then(res => setMessages(res.data));
  }, []);

  // ================= THEME CHANGE =================
  useEffect(() => {
    const handleThemeChange = () => setThemeTrigger(prev => !prev);
    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  // ================= USER ACTIONS =================
  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  // ================= POST ACTIONS =================
  const removePost = async (id) => {
    if (!window.confirm("Permanently delete this post?")) return;
    try {
      await API.delete(`/posts/${id}`);
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      alert("Error deleting post.");
    }
  };

  const viewPost = (postId) => {
    navigate(`/posts/${postId}`);
  };

  // ================= COMMENT ACTIONS =================
  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(comments.filter(c => c._id !== id));
  };

  // ================= MESSAGE ACTIONS =================
  const markAsRead = async (id) => {
    const { data } = await API.put(`/admin/messages/${id}/read`);
    setMessages(messages.map(m => (m._id === id ? data : m)));
  };

  const deleteMessage = async (id) => {
    await API.delete(`/admin/messages/${id}`);
    setMessages(messages.filter(m => m._id !== id));
  };

  // ================= THEME DETECTION =================
  const isDark = document.body.classList.contains('dark-mode');

  // ================= DESIGN SYSTEM =================
  const colors = {
    bgPink: '#FAE8ED',      
    cardPink: '#FBD5E0',    
    tablePink: '#F9B2C9',   
    darkGreen: 'rgb(12, 75, 52)',   
    white: '#FFFFFF',
    borderPink: '#E8A0B5'
  };

  const styles = {
    page: {
      backgroundColor: isDark ? '#1a0510' : colors.bgPink,
      minHeight: '90vh',
      padding: '40px 20px',
      fontFamily: '"Segoe UI", Roboto, sans-serif',
      display: 'flex',
      justifyContent: 'center',
    },
    container: {
      width: '90%',
      maxWidth: '1000px',
      backgroundColor: isDark ? '#2e091e' : colors.cardPink,
      padding: '40px',
      borderRadius: '50px',
      boxShadow: '20px 20px 60px rgba(0,0,0,0.05)',
      textAlign: 'center',
      border: `2px solid ${colors.white}`
    },
    heading: {
      fontSize: '36px',
      fontWeight: '800',
      color: colors.darkGreen,
      marginBottom: '30px',
      textTransform: 'uppercase',
      letterSpacing: '4px'
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '15px',
      marginBottom: '40px',
    },
    tabButton: {
      padding: '12px 30px',
      borderRadius: '50px',
      border: `3px solid ${colors.darkGreen}`,
      cursor: 'pointer',
      fontWeight: '770',
      fontSize: '15px',
      backgroundColor: colors.white,
      color: colors.darkGreen,
      transition: 'all 0.2s ease',
    },
    activeTab: {
      backgroundColor: colors.darkGreen,
      color: colors.white,
    },
    tableWrapper: {
      overflow: 'hidden',
      borderRadius: '25px',
      border: `3px solid ${colors.darkGreen}`,
      backgroundColor: colors.tablePink,
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse',
    },
    th: {
      padding: '20px',
      backgroundColor: colors.darkGreen,
      color: colors.white,
      textAlign: 'center',
      fontSize: '14px',
      textTransform: 'uppercase',
      letterSpacing: '2px',
    },
    td: {
      padding: '15px',
      borderBottom: `2px solid ${colors.borderPink}`,
      color: colors.darkGreen,
      fontSize: '16px',
      fontWeight: '700',
    },
    actionCell: {
      display: 'flex',
      gap: '10px',
      justifyContent: 'center',
      alignItems: 'center'
    },
    btnGreen: {
      padding: '8px 18px',
      borderRadius: '12px',
      border: 'none',
      backgroundColor: colors.darkGreen,
      color: colors.white,
      cursor: 'pointer',
      fontWeight: '700',
      fontSize: '13px',
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Admin Portal</h2>

        {/* ================= TABS ================= */}
        <div style={styles.tabs}>
          {['users', 'posts', 'comments', 'messages'].map((t) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              style={{ ...styles.tabButton, ...(tab === t ? styles.activeTab : {}) }}
            >
              {t.toUpperCase()} (
                t === 'users' ? users.length :
                t === 'posts' ? posts.length :
                t === 'comments' ? comments.length :
                messages.length
              )
            </button>
          ))}
        </div>

        {/* ================= TABLE ================= */}
        <div style={styles.tableWrapper}>
          <table style={styles.table}>
            <thead>
              {tab === 'users' && (
                <tr>
                  <th style={styles.th}>Username</th>
                  <th style={styles.th}>Email</th>
                  <th style={styles.th}>Status</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
              {tab === 'posts' && (
                <tr>
                  <th style={styles.th}>Title</th>
                  <th style={styles.th}>Author</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
              {tab === 'comments' && (
                <tr>
                  <th style={styles.th}>Author</th>
                  <th style={styles.th}>Comment</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
              {tab === 'messages' && (
                <tr>
                  <th style={styles.th}>Name</th>
                  <th style={styles.th}>Email</th>
                  <th style={styles.th}>Message</th>
                  <th style={styles.th}>Status</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
            </thead>

            <tbody>
              {tab === 'users' && users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status.toUpperCase()}</td>
                  <td style={styles.td}>
                    <button style={styles.btnGreen} onClick={() => toggleStatus(u._id)}>
                      {u.status === 'active' ? '🚫 Deactivate' : '✅ Activate'}
                    </button>
                  </td>
                </tr>
              ))}

              {tab === 'posts' && posts.map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.author?.name || 'Unknown'}</td>
                  <td style={styles.td}>
                    <div style={styles.actionCell}>
                      <button style={styles.btnGreen} onClick={() => viewPost(p._id)}>👁 View</button>
                      <button style={styles.btnGreen} onClick={() => removePost(p._id)}>🗑 Delete</button>
                    </div>
                  </td>
                </tr>
              ))}

              {tab === 'comments' && comments.map(c => (
                <tr key={c._id}>
                  <td style={styles.td}>{c.author?.name}</td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>
                    <button style={styles.btnGreen} onClick={() => deleteComment(c._id)}>🗑 Remove</button>
                  </td>
                </tr>
              ))}

              {tab === 'messages' && messages.map(m => (
                <tr key={m._id}>
                  <td style={styles.td}>{m.name}</td>
                  <td style={styles.td}>{m.email}</td>
                  <td style={styles.td}>{m.body}</td>
                  <td style={styles.td}>{m.status.toUpperCase()}</td>
                  <td style={{ ...styles.td, ...styles.actionCell }}>
                    {m.status === 'new' && (
                      <button style={styles.btnGreen} onClick={() => markAsRead(m._id)}>✅ Mark Read</button>
                    )}
                    <button style={styles.btnGreen} onClick={() => deleteMessage(m._id)}>🗑 Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminPage;
